import { useEffect, useState } from "react";
import api from "../api";
const money = n => (Number(n||0)).toLocaleString("vi-VN")+" ₫";

export default function Payments() {
    const [rows, setRows] = useState([]);
    const [contracts, setContracts] = useState([]);
    const [form, setForm] = useState({ contractId: "", date: "", amount: "", method: "TRANSFER", status: "PENDING", confirmer: "" });
    const [saving, setSaving] = useState(false);
    const [loading, setLoading] = useState(true);

    const load = async () => {
        setLoading(true);
        try {
            const [p, c] = await Promise.all([
                api.get("/api/payments"),
                api.get("/api/contracts"),
            ]);
            setRows(p.data||[]);
            setContracts(c.data||[]);
            if (!form.contractId && c.data?.length) setForm(s=>({...s, contractId: c.data[0].id}));
        } finally {
            setLoading(false);
        }
    };
    useEffect(()=>{ load(); },[]);

    const save = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.post("/api/payments", {
                contractId: Number(form.contractId),
                paymentDate: form.date || form.paymentDate,
                date: form.date,  // nếu API nhận "date"
                amount: Number(form.amount),
                method: form.method,
                status: form.status,
                confirmer: form.confirmer
            });
            setForm(s=>({...s, date:"", amount:"", confirmer:""}));
            await load();
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Thanh toán</h2>
                    <p className="text-sm text-slate-500">Quản lý các đợt thanh toán theo hợp đồng</p>
                </div>
            </div>

            <form onSubmit={save} className="bg-white rounded-2xl border border-indigo-100 shadow p-4 grid grid-cols-1 md:grid-cols-6 gap-3">
                <select className="px-3 py-2 rounded-lg border" value={form.contractId} onChange={e=>setForm(s=>({...s,contractId:e.target.value}))}>
                    {contracts.map(c=>(<option key={c.id} value={c.id}>{c.code}</option>))}
                </select>
                <input type="date" className="px-3 py-2 rounded-lg border" value={form.date} onChange={e=>setForm(s=>({...s,date:e.target.value}))}/>
                <input type="number" className="px-3 py-2 rounded-lg border" placeholder="Số tiền" value={form.amount} onChange={e=>setForm(s=>({...s,amount:e.target.value}))}/>
                <select className="px-3 py-2 rounded-lg border" value={form.method} onChange={e=>setForm(s=>({...s,method:e.target.value}))}>
                    <option value="TRANSFER">Chuyển khoản</option>
                    <option value="CASH">Tiền mặt</option>
                </select>
                <input className="px-3 py-2 rounded-lg border" placeholder="Người xác nhận" value={form.confirmer} onChange={e=>setForm(s=>({...s,confirmer:e.target.value}))}/>
                <button disabled={saving} className="px-3 py-2 rounded-lg bg-indigo-600 text-white">{saving?"Đang lưu...":"Thêm"}</button>
            </form>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full">
                        <thead className="bg-indigo-50">
                        <tr className="text-left text-slate-600">
                            <th className="px-4 py-3">Mã HĐ</th>
                            <th className="px-4 py-3">Ngày</th>
                            <th className="px-4 py-3">Số tiền</th>
                            <th className="px-4 py-3">Phương thức</th>
                            <th className="px-4 py-3">Trạng thái</th>
                            <th className="px-4 py-3">Xác nhận</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {!loading && rows.map(p=>{
                            const ct = contracts.find(c=>c.id===p.contractId);
                            return (
                                <tr key={p.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{ct?.code || "-"}</td>
                                    <td className="px-4 py-3">{p.date || p.paymentDate}</td>
                                    <td className="px-4 py-3">{money(p.amount)}</td>
                                    <td className="px-4 py-3">{p.method}</td>
                                    <td className="px-4 py-3">{p.status}</td>
                                    <td className="px-4 py-3">{p.confirmer||"-"}</td>
                                </tr>
                            );
                        })}
                        {loading && <tr><td className="px-4 py-3" colSpan={6}>Đang tải...</td></tr>}
                        {!loading && rows.length===0 && <tr><td className="px-4 py-3" colSpan={6}>Không có dữ liệu</td></tr>}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
